    public Object parseLedgerEntry(Object item, Object... optionalArgs)
    {
        Object currency = Helpers.getArg(optionalArgs, 0, null);
        Object amount = this.safeString(item, "amount");
        Object direction = null;
        if (Helpers.isTrue(Precise.stringLe(amount, "0")))
        {
            direction = "out";
            amount = Precise.stringMul("-1", amount);
        } else
        {
            direction = "in";
        }
        Object currencyId = this.safeString(item, "currency");
        currency = this.safeCurrency(currencyId, currency);
        Object code = this.safeCurrencyCode(currencyId, currency);
        Object timestampString = this.safeString(item, "timestamp");
        Object timestamp = this.parse8601(timestampString);
        Object type = this.safeString(item, "type");
        final Object finalDirection = direction;
        final Object finalAmount = amount;
        return this.safeLedgerEntry(new java.util.HashMap<String, Object>() {{
            put( "info", item );
            put( "id", CexCore.this.safeString(item, "transactionId") );
            put( "direction", finalDirection );
            put( "account", CexCore.this.safeString(item, "accountId", "") );
            put( "referenceAccount", null );
            put( "referenceId", null );
            put( "type", CexCore.this.parseLedgerEntryType(type) );
            put( "currency", code );
            put( "amount", CexCore.this.parseNumber(finalAmount) );
            put( "timestamp", timestamp );
            put( "datetime", CexCore.this.iso8601(timestamp) );
            put( "before", null );
            put( "after", null );
            put( "status", null );
            put( "fee", null );
        }}, currency);
    }

